export const ConfirmSupplierBillParams = zod.object({
  id: zod.coerce.number(),
});

export const ConfirmSupplierBillResponse = zod.object({
  bill: zod.object({
    id: zod.number(),
    supplierId: zod.number(),
    supplierName: zod.string(),
    billNumber: zod.string(),
    billDate: zod.string(),
    totalAmount: zod.number(),
    status: zod.string(),
    imageUrl: zod.string().nullable(),
    rawText: zod.string().nullable(),
    confidence: zod.number().nullable(),
    notes: zod.string().nullable(),
    createdAt: zod.string(),
    items: zod.array(
      zod.object({
        id: zod.number(),
        billId: zod.number(),
        productId: zod.number().nullable(),
        articleCode: zod.string(),
        productName: zod.string(),
        quantity: zod.number(),
        unitPrice: zod.number(),
        totalPrice: zod.number(),
      }),
    ),
  }),
  stockUpdates: zod.array(
    zod.object({
      articleCode: zod.string(),
      productName: zod.string(),
      quantityAdded: zod.number(),
      newStock: zod.number(),
    }),
  ),
});

/**
 * @summary List all payment clearances
 */
export const ListPaymentClearancesResponseItem = zod.object({
  id: zod.number(),
  amount: zod.number(),
  notes: zod.string().nullish(),
  date: zod.coerce.date(),
  retailerName: zod.string().nullish(),
  vendorName: zod.string().nullish(),
});
export const ListPaymentClearancesResponse = zod.array(
  ListPaymentClearancesResponseItem,
);

/**
 * @summary Generate a payment clearance - deducts from retailer credit and records vendor payment
 */
